package com.bank.app.transaction;

import android.content.Context;
import android.content.pm.ApplicationInfo;
import android.content.pm.PackageManager;
import android.os.Build;
import android.provider.Settings;

import java.io.File;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public class DeviceIntegrityChecker {
    private Context context;
    private static final List<String> ROOT_INDICATORS = Arrays.asList(
        "/system/app/Superuser.apk",
        "/sbin/su",
        "/system/bin/su",
        "/system/xbin/su",
        "/data/local/xbin/su",
        "/data/local/bin/su",
        "/system/sd/xbin/su",
        "/system/bin/failsafe/su",
        "/data/local/su",
        "/su/bin/su"
    );
    
    private static final List<String> DANGEROUS_PACKAGES = Arrays.asList(
        "com.noshufou.android.su",
        "com.thirdparty.superuser",
        "eu.chainfire.supersu",
        "com.koushikdutta.superuser",
        "com.zachspong.temprootremovejb",
        "com.ramdroid.appquarantine",
        "com.topjohnwu.magisk"
    );
    
    public DeviceIntegrityChecker(Context context) {
        this.context = context;
    }
    
    public IntegrityCheckResult performComprehensiveCheck() {
        List<String> failures = new ArrayList<>();
        
        // Check for root
        if (isDeviceRooted()) {
            failures.add("Device appears to be rooted");
        }
        
        // Check for emulator
        if (isEmulator()) {
            failures.add("Running on emulator");
        }
        
        // Check for debugging
        if (isDebuggable()) {
            failures.add("App is debuggable");
        }
        
        // Check for USB debugging
        if (isUsbDebuggingEnabled()) {
            failures.add("USB debugging is enabled");
        }
        
        // Check for dangerous apps
        List<String> dangerousApps = checkForDangerousApps();
        if (!dangerousApps.isEmpty()) {
            failures.add("Dangerous apps detected: " + String.join(", ", dangerousApps));
        }
        
        // Check for hooking frameworks
        if (isHookingFrameworkDetected()) {
            failures.add("Hooking framework detected");
        }
        
        boolean passed = failures.isEmpty();
        String reason = passed ? "All checks passed" : String.join("; ", failures);
        
        return new IntegrityCheckResult(passed, reason);
    }
    
    private boolean isDeviceRooted() {
        // Check for root binaries
        for (String path : ROOT_INDICATORS) {
            if (new File(path).exists()) {
                return true;
            }
        }
        
        // Check for root packages
        PackageManager pm = context.getPackageManager();
        for (String pkg : DANGEROUS_PACKAGES) {
            try {
                pm.getPackageInfo(pkg, 0);
                return true;
            } catch (PackageManager.NameNotFoundException e) {
                // Package not found, continue
            }
        }
        
        // Check build tags
        String buildTags = Build.TAGS;
        if (buildTags != null && buildTags.contains("test-keys")) {
            return true;
        }
        
        // Try to execute su command
        try {
            Process process = Runtime.getRuntime().exec(new String[]{"/system/xbin/which", "su"});
            return process.waitFor() == 0;
        } catch (Exception e) {
            // Command failed, likely not rooted
        }
        
        return false;
    }
    
    private boolean isEmulator() {
        return Build.FINGERPRINT.startsWith("generic")
            || Build.FINGERPRINT.startsWith("unknown")
            || Build.MODEL.contains("google_sdk")
            || Build.MODEL.contains("Emulator")
            || Build.MODEL.contains("Android SDK built for x86")
            || Build.MANUFACTURER.contains("Genymotion")
            || (Build.BRAND.startsWith("generic") && Build.DEVICE.startsWith("generic"))
            || "google_sdk".equals(Build.PRODUCT)
            || Build.HARDWARE.contains("goldfish")
            || Build.HARDWARE.contains("ranchu");
    }
    
    private boolean isDebuggable() {
        return (context.getApplicationInfo().flags & ApplicationInfo.FLAG_DEBUGGABLE) != 0;
    }
    
    private boolean isUsbDebuggingEnabled() {
        try {
            return Settings.Secure.getInt(context.getContentResolver(),
                Settings.Global.ADB_ENABLED, 0) == 1;
        } catch (Exception e) {
            return false;
        }
    }
    
    private List<String> checkForDangerousApps() {
        List<String> found = new ArrayList<>();
        PackageManager pm = context.getPackageManager();
        
        for (String pkg : DANGEROUS_PACKAGES) {
            try {
                pm.getPackageInfo(pkg, 0);
                found.add(pkg);
            } catch (PackageManager.NameNotFoundException e) {
                // Package not found
            }
        }
        
        return found;
    }
    
    private boolean isHookingFrameworkDetected() {
        try {
            // Check for Xposed
            throw new Exception();
        } catch (Exception e) {
            for (StackTraceElement element : e.getStackTrace()) {
                if (element.getClassName().contains("de.robv.android.xposed")) {
                    return true;
                }
            }
        }
        
        // Check for Frida
        try {
            File frida = new File("/data/local/tmp/frida-server");
            if (frida.exists()) {
                return true;
            }
        } catch (Exception e) {
            // Ignore
        }
        
        return false;
    }
}

