// TransactionValidator.java
package com.bank.app.transaction;

import android.util.Patterns;

public class TransactionValidator {
    private static final double MAX_TRANSACTION_AMOUNT = 50000.0;
    private static final double MIN_TRANSACTION_AMOUNT = 0.01;
    
    public ValidationResult validate(Transaction transaction) {
        if (transaction == null) {
            return new ValidationResult(false, "Transaction is null");
        }
        
        if (transaction.getAmount() < MIN_TRANSACTION_AMOUNT) {
            return new ValidationResult(false, "Amount too small");
        }
        
        if (transaction.getAmount() > MAX_TRANSACTION_AMOUNT) {
            return new ValidationResult(false, "Amount exceeds maximum limit");
        }
        
        if (transaction.getFromAccount() == null || transaction.getFromAccount().isEmpty()) {
            return new ValidationResult(false, "Invalid source account");
        }
        
        if (transaction.getToAccount() == null || transaction.getToAccount().isEmpty()) {
            return new ValidationResult(false, "Invalid destination account");
        }
        
        if (transaction.getFromAccount().equals(transaction.getToAccount())) {
            return new ValidationResult(false, "Source and destination accounts cannot be the same");
        }
        
        return new ValidationResult(true, "Validation passed");
    }
}

