package com.bank.app.account;

import android.content.Context;
import android.content.SharedPreferences;
import android.security.keystore.KeyGenParameterSpec;
import android.security.keystore.KeyProperties;
import android.util.Base64;
import android.util.Log;

import androidx.security.crypto.EncryptedSharedPreferences;
import androidx.security.crypto.MasterKey;

import java.security.SecureRandom;
import java.text.NumberFormat;
import java.util.Currency;
import java.util.Locale;

import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.GCMParameterSpec;

public class AccountBalanceManager {
    private static final String TAG = "AccountBalanceManager";
    private static final String PREFS_NAME = "encrypted_account_prefs";
    private static final String KEY_BALANCE = "account_balance_";
    private static final int GCM_TAG_LENGTH = 128;
    
    private Context context;
    private SharedPreferences encryptedPrefs;
    private SecretKey encryptionKey;
    
    public AccountBalanceManager(Context context) {
        this.context = context;
        initializeSecureStorage();
        initializeEncryption();
    }
    
    private void initializeSecureStorage() {
        try {
            MasterKey masterKey = new MasterKey.Builder(context)
                .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
                .build();
            
            encryptedPrefs = EncryptedSharedPreferences.create(
                context,
                PREFS_NAME,
                masterKey,
                EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
            );
        } catch (Exception e) {
            Log.e(TAG, "Failed to initialize encrypted storage", e);
        }
    }
    
    private void initializeEncryption() {
        try {
            KeyGenerator keyGenerator = KeyGenerator.getInstance("AES");
            keyGenerator.init(256);
            encryptionKey = keyGenerator.generateKey();
        } catch (Exception e) {
            Log.e(TAG, "Encryption initialization failed", e);
        }
    }
    
    public String getFormattedBalance(String accountId) {
        double balance = getBalance(accountId);
        NumberFormat formatter = NumberFormat.getCurrencyInstance(Locale.US);
        formatter.setCurrency(Currency.getInstance("USD"));
        
        // Obfuscate balance display for security
        String formatted = formatter.format(balance);
        return formatted;
    }
    
    public double getBalance(String accountId) {
        try {
            String encryptedBalance = encryptedPrefs.getString(KEY_BALANCE + accountId, null);
            if (encryptedBalance != null) {
                return Double.parseDouble(decryptData(encryptedBalance));
            }
        } catch (Exception e) {
            Log.e(TAG, "Failed to retrieve balance", e);
        }
        return 0.0;
    }
    
    public boolean updateBalance(String accountId, double newBalance) {
        try {
            String encryptedBalance = encryptData(String.valueOf(newBalance));
            encryptedPrefs.edit()
                .putString(KEY_BALANCE + accountId, encryptedBalance)
                .apply();
            return true;
        } catch (Exception e) {
            Log.e(TAG, "Failed to update balance", e);
            return false;
        }
    }
    
    public boolean deductAmount(String accountId, double amount) {
        double currentBalance = getBalance(accountId);
        if (currentBalance >= amount) {
            return updateBalance(accountId, currentBalance - amount);
        }
        return false;
    }
    
    public boolean addAmount(String accountId, double amount) {
        double currentBalance = getBalance(accountId);
        return updateBalance(accountId, currentBalance + amount);
    }
    
    private String encryptData(String data) {
        try {
            Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
            byte[] iv = new byte[12];
            new SecureRandom().nextBytes(iv);
            GCMParameterSpec spec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
            cipher.init(Cipher.ENCRYPT_MODE, encryptionKey, spec);
            
            byte[] encrypted = cipher.doFinal(data.getBytes());
            
            byte[] combined = new byte[iv.length + encrypted.length];
            System.arraycopy(iv, 0, combined, 0, iv.length);
            System.arraycopy(encrypted, 0, combined, iv.length, encrypted.length);
            
            return Base64.encodeToString(combined, Base64.NO_WRAP);
        } catch (Exception e) {
            Log.e(TAG, "Encryption failed", e);
            return null;
        }
    }
    
    private String decryptData(String encryptedData) {
        try {
            byte[] combined = Base64.decode(encryptedData, Base64.NO_WRAP);
            
            byte[] iv = new byte[12];
            byte[] encrypted = new byte[combined.length - 12];
            System.arraycopy(combined, 0, iv, 0, 12);
            System.arraycopy(combined, 12, encrypted, 0, encrypted.length);
            
            Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
            GCMParameterSpec spec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
            cipher.init(Cipher.DECRYPT_MODE, encryptionKey, spec);
            
            byte[] decrypted = cipher.doFinal(encrypted);
            return new String(decrypted);
        } catch (Exception e) {
            Log.e(TAG, "Decryption failed", e);
            return null;
        }
    }
}

// SecureBalanceDisplay.java
package com.bank.app.account;

import android.content.Context;
import android.graphics.Canvas;
import android.graphics.Paint;
import android.graphics.Rect;
import android.util.AttributeSet;
import android.view.View;

public class SecureBalanceDisplay extends View {
    private String balance = "****";
    private boolean isVisible = false;
    private Paint textPaint;
    
    public SecureBalanceDisplay(Context context) {
        super(context);
        init();
    }
    
    public SecureBalanceDisplay(Context context, AttributeSet attrs) {
        super(context, attrs);
        init();
    }
    
    private void init() {
        textPaint = new Paint();
        textPaint.setTextSize(48);
        textPaint.setAntiAlias(true);
        
        // Prevent screenshots
        setLayerType(View.LAYER_TYPE_HARDWARE, null);
    }
    
    public void setBalance(String balance) {
        this.balance = balance;
        invalidate();
    }
    
    public void toggleVisibility() {
        isVisible = !isVisible;
        invalidate();
    }
    
    @Override
    protected void onDraw(Canvas canvas) {
        super.onDraw(canvas);
        
        String displayText = isVisible ? balance : "****";
        Rect bounds = new Rect();
        textPaint.getTextBounds(displayText, 0, displayText.length(), bounds);
        
        int x = (getWidth() - bounds.width()) / 2;
        int y = (getHeight() + bounds.height()) / 2;
        
        canvas.drawText(displayText, x, y, textPaint);
    }
}